package org.apache.beam.sdk.options;

import java.util.ArrayList;
import java.util.Collections;
import java.util.List;
import org.apache.beam.vendor.guava.v32_1_2_jre.com.google.common.base.MoreObjects;

/**
 * Represents the result of validating {@link PipelineOptions}. Contains a list of validation errors
 * and warnings.
 */
public class ValidationResult {
  private final List<String> errors;
  private final List<String> warnings;

  /**
   * Creates a new ValidationResult with the given errors and warnings.
   *
   * @param errors A list of validation error messages.
   * @param warnings A list of validation warning messages.
   */
  public ValidationResult(List<String> errors, List<String> warnings) {
    this.errors = Collections.unmodifiableList(new ArrayList<>(errors));
    this.warnings = Collections.unmodifiableList(new ArrayList<>(warnings));
  }

  /**
   * Returns the list of validation errors. An empty list means no errors were found.
   *
   * @return An immutable list of error messages.
   */
  public List<String> getErrors() {
    return errors;
  }

  /**
   * Returns the list of validation warnings. Warnings do not prevent validation from passing, but
   * may indicate potential issues.
   *
   * @return An immutable list of warning messages.
   */
  public List<String> getWarnings() {
    return warnings;
  }

  /**
   * Returns true if the validation passed (i.e., there are no errors).
   *
   * @return True if validation passed (no errors), false otherwise.
   */
  public boolean isValid() {
    return errors.isEmpty();
  }

  @Override
  public String toString() {
    return MoreObjects.toStringHelper(this)
        .add("errors", errors)
        .add("warnings", warnings)
        .add("isValid", isValid())
        .toString();
  }
}

