  private static String getDescription(Method method) {
    Description description = method.getAnnotation(Description.class);
    return description == null ? "" : description.value();
  }

  /**
   * Builder for accumulating and executing validation rules on PipelineOptions. Follows the Builder
   * pattern to allow flexible validation rule composition.
   *
   * <p>Example usage:
   *
   * <pre>{@code
   * ValidationResult result = PipelineOptionsValidator.builder()
   *     .validateRequired(options, RequiredOptions.class)
   *     .validateType(options, MyOptions.class)
   *     .validate(options);
   * }</pre>
   */
  public static class Builder {
    private final List<ValidationRule> rules = new ArrayList<>();

    /**
     * Adds a validation rule to check for required fields in the given PipelineOptions interface.
     *
     * @param options The PipelineOptions instance to validate.
     * @param klass The PipelineOptions interface to validate against.
     * @return This Builder instance for method chaining.
     */
    public Builder validateRequired(PipelineOptions options, Class<? extends PipelineOptions> klass) {
      checkNotNull(options);
      checkNotNull(klass);
      rules.add(new RequiredValidationRule(klass, options));
      return this;
    }

    /**
     * Adds a validation rule to check that options conform to expected types.
     *
     * @param options The PipelineOptions instance to validate.
     * @param klass The PipelineOptions interface to validate against.
     * @return This Builder instance for method chaining.
     */
    public Builder validateType(PipelineOptions options, Class<? extends PipelineOptions> klass) {
      checkNotNull(options);
      checkNotNull(klass);
      rules.add(new TypeValidationRule(klass, options));
      return this;
    }

    /**
     * Adds a validation rule to check that numeric option values fall within expected ranges.
     *
     * @param options The PipelineOptions instance to validate.
     * @param klass The PipelineOptions interface to validate against.
     * @return This Builder instance for method chaining.
     */
    public Builder validateRange(PipelineOptions options, Class<? extends PipelineOptions> klass) {
      checkNotNull(options);
      checkNotNull(klass);
      rules.add(new RangeValidationRule(klass, options));
      return this;
    }

    /**
     * Executes all accumulated validation rules and returns a {@link ValidationResult}.
     *
     * @param options The PipelineOptions to validate.
     * @return A ValidationResult containing any errors and warnings found.
     */
    public ValidationResult validate(PipelineOptions options) {
      checkNotNull(options);
      List<String> errors = new ArrayList<>();
      List<String> warnings = new ArrayList<>();

      for (ValidationRule rule : rules) {
        rule.validate(errors, warnings);
      }

      return new ValidationResult(errors, warnings);
    }
  }

  /** Interface for validation rules. */
  private interface ValidationRule {
    void validate(List<String> errors, List<String> warnings);
  }

  /** Validation rule that checks required fields. */
  private static class RequiredValidationRule implements ValidationRule {
    private final Class<? extends PipelineOptions> klass;
    private final PipelineOptions options;

    RequiredValidationRule(Class<? extends PipelineOptions> klass, PipelineOptions options) {
      this.klass = klass;
      this.options = options;
    }

    @Override
    public void validate(List<String> errors, List<String> warnings) {
      try {
        PipelineOptionsValidator.validate(klass, options);
      } catch (IllegalArgumentException e) {
        errors.add(e.getMessage());
      }
    }
  }

  /** Validation rule that checks type correctness. */
  private static class TypeValidationRule implements ValidationRule {
    private final Class<? extends PipelineOptions> klass;
    private final PipelineOptions options;

    TypeValidationRule(Class<? extends PipelineOptions> klass, PipelineOptions options) {
      this.klass = klass;
      this.options = options;
    }

    @Override
    public void validate(List<String> errors, List<String> warnings) {
      // Type validation: ensure the options can be cast to the target class
      try {
        options.as(klass);
      } catch (Exception e) {
        errors.add("Type validation failed: " + e.getMessage());
      }
    }
  }

