package org.apache.beam.sdk.options;

import static org.hamcrest.MatcherAssert.assertThat;
import static org.hamcrest.Matchers.containsString;
import static org.hamcrest.Matchers.empty;
import static org.hamcrest.Matchers.hasSize;
import static org.junit.Assert.assertFalse;
import static org.junit.Assert.assertTrue;

import org.apache.beam.sdk.testing.CrashingRunner;
import org.junit.Test;
import org.junit.runner.RunWith;
import org.junit.runners.JUnit4;

/** Tests for {@link PipelineOptionsValidator} with Builder pattern. */
@RunWith(JUnit4.class)
public class PipelineOptionsValidatorBuilderTest {

  /** A test interface with required fields. */
  public interface RequiredOptions extends PipelineOptions {
    @Validation.Required
    @Description("Required field for testing")
    String getRequiredField();

    void setRequiredField(String value);

    @Validation.Required
    @Description("Another required field")
    Integer getRequiredNumber();

    void setRequiredNumber(Integer value);
  }

  /** A test interface with optional fields. */
  public interface OptionalOptions extends PipelineOptions {
    @Description("Optional field")
    String getOptionalField();

    void setOptionalField(String value);
  }

  @Test
  public void testValidationResultWithNoErrors() {
    ValidationResult result = PipelineOptionsValidator.builder().validate(getBasicOptions());

    assertTrue("Should be valid when no validation rules added", result.isValid());
    assertThat("Should have no errors", result.getErrors(), empty());
    assertThat("Should have no warnings", result.getWarnings(), empty());
  }

  @Test
  public void testValidationResultWithErrors() {
    RequiredOptions options = PipelineOptionsFactory.as(RequiredOptions.class);
    options.setRunner(CrashingRunner.class);
    // Don't set required fields

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRequired(options, RequiredOptions.class)
            .validate(options);

    assertFalse("Should be invalid when required fields are missing", result.isValid());
    assertThat("Should have errors", result.getErrors(), hasSize(1));
    assertThat(
        "Error message should mention missing required value",
        result.getErrors().get(0),
        containsString("Missing required value"));
  }

  @Test
  public void testValidationResultIsImmutable() {
    ValidationResult result = PipelineOptionsValidator.builder().validate(getBasicOptions());

    // Attempting to modify the returned lists should not affect the result
    result.getErrors().add("Should not work");
    result.getWarnings().add("Should not work");

    assertThat("Errors list should remain empty", result.getErrors(), empty());
    assertThat("Warnings list should remain empty", result.getWarnings(), empty());
  }

  @Test
  public void testBuilderWithRequiredValidation() {
    RequiredOptions options = PipelineOptionsFactory.as(RequiredOptions.class);
    options.setRunner(CrashingRunner.class);
    options.setRequiredField("test value");
    options.setRequiredNumber(42);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRequired(options, RequiredOptions.class)
            .validate(options);

    assertTrue("Should be valid when all required fields are set", result.isValid());
  }

  @Test
  public void testBuilderWithTypeValidation() {
    PipelineOptions options = PipelineOptionsFactory.create();
    options.setRunner(CrashingRunner.class);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateType(options, PipelineOptions.class)
            .validate(options);

    assertTrue("Should be valid for basic PipelineOptions type", result.isValid());
  }

  @Test
  public void testBuilderWithMultipleValidations() {
    RequiredOptions options = PipelineOptionsFactory.as(RequiredOptions.class);
    options.setRunner(CrashingRunner.class);
    options.setRequiredField("test");
    options.setRequiredNumber(100);

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRequired(options, RequiredOptions.class)
            .validateType(options, RequiredOptions.class)
            .validate(options);

    assertTrue("Should pass all validations", result.isValid());
  }

  @Test
  public void testBuilderMethodChaining() {
    OptionalOptions options = PipelineOptionsFactory.as(OptionalOptions.class);
    options.setRunner(CrashingRunner.class);

    // Test that method chaining works
    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRequired(options, OptionalOptions.class)
            .validateType(options, OptionalOptions.class)
            .validate(options);

    assertTrue("Should complete method chaining successfully", result.isValid());
  }

  @Test
  public void testValidationResultToString() {
    ValidationResult result = PipelineOptionsValidator.builder().validate(getBasicOptions());

    String resultString = result.toString();
    assertTrue("toString should contain 'isValid'", resultString.contains("isValid"));
    assertTrue("toString should contain 'errors'", resultString.contains("errors"));
    assertTrue("toString should contain 'warnings'", resultString.contains("warnings"));
  }

  @Test
  public void testBuilderWithMissingRequiredField() {
    RequiredOptions options = PipelineOptionsFactory.as(RequiredOptions.class);
    options.setRunner(CrashingRunner.class);
    options.setRequiredField("test");
    // Don't set required number

    ValidationResult result =
        PipelineOptionsValidator.builder()
            .validateRequired(options, RequiredOptions.class)
            .validate(options);

    assertFalse("Should be invalid when one required field is missing", result.isValid());
    assertThat("Should have at least one error", result.getErrors().size() >= 1);
  }

  private PipelineOptions getBasicOptions() {
    PipelineOptions options = PipelineOptionsFactory.create();
    options.setRunner(CrashingRunner.class);
    return options;
  }
}

